<?php
namespace Tests\Unit;
use App\Services\Trading\PositionManagementRiskEvaluationService;use Tests\TestCase;
class PositionManagementRiskEvaluationServiceTest extends TestCase
{protected function state($price=89,array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_position_state_v1','status'=>'condition_observed','position_id'=>'position-bumi-1','ticker'=>'BUMI','position_side'=>'long','price_snapshot'=>['entry_price'=>100,'current_reference_price'=>$price,'currency'=>'IDR'],'metrics'=>['unrealized_pnl_pct'=>round(($price-100)/100*100,6),'unrealized_pnl_amount'=>round(($price-100)*1000,6)],'protection_checks'=>['stop_reference_available'=>true,'stop_reference_breached'=>$price<=90,'target_reference_available'=>true,'target_reference_reached'=>$price>=110],'reason_codes'=>[]],$over);}protected function candidate($type='protection_breach_review',$condition='stop_reference_breached',array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_position_management_candidate_v1','status'=>'policy_hypothesis','candidate_id'=>str_repeat('a',64),'candidate_type'=>$type,'position_id'=>'position-bumi-1','ticker'=>'BUMI','position_side'=>'long','condition'=>$condition,'policy_id'=>'policy-1','policy_rule_id'=>'rule-1'], $over);}protected function policy($condition='stop_reference_breached'):array{return ['schema_version'=>'trading_position_management_policy_evaluation_v1','status'=>'matched_reference_rule','policy_id'=>'policy-1','state_condition'=>$condition];}protected function managed():array{return ['quantity'=>1000,'existing_protection'=>['stop_reference'=>['price'=>90],'target_reference'=>['price'=>110]]];}
public function test_entry_scope_and_missing_inputs():void{$svc=new PositionManagementRiskEvaluationService();$this->assertSame('not_required',$svc->evaluate(['decision_scope'=>'entry_evaluation'])['status']);$this->assertSame('unavailable',$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'policy_evaluation'=>$this->policy()])['status']);}
public function test_stop_breach_metrics_and_nulls():void{$r=(new PositionManagementRiskEvaluationService())->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(89),'management_candidate'=>$this->candidate(),'policy_evaluation'=>$this->policy(),'managed_position'=>$this->managed()]);$this->assertSame('condition_risk_observed',$r['status']);$this->assertEquals(100000,$r['metrics']['entry_reference_notional']);$this->assertEquals(89000,$r['metrics']['current_reference_notional']);$this->assertEquals(-11,$r['metrics']['unrealized_pnl_pct']);$this->assertEquals(-11000,$r['metrics']['unrealized_pnl_amount']);$this->assertEquals(10,$r['metrics']['planned_stop_loss_per_unit']);$this->assertEquals(10000,$r['metrics']['planned_stop_loss_amount']);$this->assertEquals(1,$r['metrics']['stop_breach_depth_per_unit']);$this->assertEquals(1000,$r['metrics']['stop_breach_amount']);$this->assertSame(1.111111,$r['metrics']['stop_breach_depth_pct']);$this->assertNull($r['metrics']['net_exit_value']);$this->assertNull($r['metrics']['realized_pnl']);$this->assertNull($r['metrics']['portfolio_impact_after_action']);}
public function test_target_missing_stale_and_validation():void{$svc=new PositionManagementRiskEvaluationService();$t=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(111),'management_candidate'=>$this->candidate('target_reached_review','target_reference_reached'),'policy_evaluation'=>$this->policy('target_reference_reached'),'managed_position'=>$this->managed()]);$this->assertEquals(1,$t['metrics']['target_exceedance_per_unit']);$this->assertEquals(1000,$t['metrics']['target_exceedance_amount']);$this->assertSame(0.909091,$t['metrics']['target_exceedance_pct']);$m=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(95,['status'=>'partial','protection_checks'=>['stop_reference_available'=>false,'stop_reference_breached'=>null,'target_reference_available'=>true,'target_reference_reached'=>false]]),'management_candidate'=>$this->candidate('protection_missing_review','protection_reference_missing'),'policy_evaluation'=>$this->policy('protection_reference_missing'),'managed_position'=>$this->managed()]);$this->assertSame('partial',$m['status']);$this->assertNull($m['metrics']['planned_stop_loss_per_unit']);$s=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(89,['reason_codes'=>['POSITION_MARKET_OBSERVATION_STALE']]),'management_candidate'=>$this->candidate(),'policy_evaluation'=>$this->policy(),'managed_position'=>$this->managed()]);$this->assertSame('blocked',$s['status']);$s['metrics']['realized_pnl']=1;$this->expectException(\InvalidArgumentException::class);$svc->validateRisk($s);}}
